arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train and save the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var rawData = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to boolean Label column
var labelMappingPipeline = mlContext.Transforms.CustomMapping<CustomerDataRaw, CustomerDataLabeled>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: null);

var labeledData = labelMappingPipeline.Fit(rawData).Transform(rawData);

var split = mlContext.Data.TrainTestSplit(labeledData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerDataRaw.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerDataRaw.Age),
        nameof(CustomerDataRaw.Income),
        "RegionEncoded",
        nameof(CustomerDataRaw.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");

// Save full pipeline (label mapping + training) for prediction
var fullPipeline = labelMappingPipeline.Append(pipeline);
var fullModel = fullPipeline.Fit(rawData);
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(fullModel, rawData.Schema, modelPath);

// Register pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<CustomerDataRaw, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerDataRaw, ChurnPrediction> pool) =>
{
    var data = new CustomerDataRaw
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory,
        Churned = ""
    };
    var result = pool.Predict(data);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability,
        Score = result.Score
    });
});

app.Run();

// --- Data models ---

public class CustomerDataRaw
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class CustomerDataLabeled
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

