7. // --- Train and save the model at startup ---
8. var mlContext = new MLContext(seed: 42);
9. var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
10. 
11. var rawData = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(
12.     dataPath, hasHeader: true, separatorChar: ',');
13. 
14. // Map "Yes"/"No" string to boolean Label column
15. var labelMappingPipeline = mlContext.Transforms.CustomMapping<CustomerDataRaw, CustomerDataLabeled>(
16.     (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
17.     contractName: null);
18. 
19. var labeledData = labelMappingPipeline.Fit(rawData).Transform(rawData);
20. 
21. var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerDataRaw.Region))
22.     .Append(mlContext.Transforms.Concatenate("Features",
23.         nameof(CustomerDataRaw.Age),
24.         nameof(CustomerDataRaw.Income),
25.         "RegionEncoded",
26.         nameof(CustomerDataRaw.PurchaseHistory)))
27.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
28.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
29.         labelColumnName: "Label", featureColumnName: "Features"));
30. 
31. // Use train/test split when dataset is large enough; otherwise train on all data
32. var rowCount = (int)labeledData.GetColumn<bool>("Label").Count();
33. ITransformer model;
34. if (rowCount >= 20)
35. {
36.     var split = mlContext.Data.TrainTestSplit(labeledData, testFraction: 0.2);
37.     model = pipeline.Fit(split.TrainSet);
38.     var predictions = model.Transform(split.TestSet);
39.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
40.     Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
41.     Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
42.     Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
43. }
44. else
45. {
46.     Console.WriteLine($"Dataset has {rowCount} rows — too small for train/test split. Training on all data.");
47.     Console.WriteLine("Add more rows for meaningful evaluation metrics.");
48.     model = pipeline.Fit(labeledData);
49. }
50. 
51. // Save full pipeline (label mapping + training) for prediction
52. var fullPipeline = labelMappingPipeline.Append(pipeline);
53. var fullModel = fullPipeline.Fit(rawData);
54. var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
