using System.Globalization;
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Load CSV and convert "Yes"/"No" label to bool ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var rows = File.ReadAllLines(dataPath)
    .Skip(1)
    .Where(line => !string.IsNullOrWhiteSpace(line))
    .Select(line =>
    {
        var cols = line.Split(',');
        return new CustomerData
        {
            Age = float.Parse(cols[0], CultureInfo.InvariantCulture),
            Income = float.Parse(cols[1], CultureInfo.InvariantCulture),
            Region = cols[2].Trim(),
            PurchaseHistory = float.Parse(cols[3], CultureInfo.InvariantCulture),
            Label = cols[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase)
        };
    })
    .ToList();

var dataView = mlContext.Data.LoadFromEnumerable(rows);

// --- Build training pipeline ---
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

// Use train/test split when dataset is large enough; otherwise train on all data
ITransformer model;
if (rows.Count >= 20)
{
    var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
    model = pipeline.Fit(split.TrainSet);
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
    Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
}
else
{
    Console.WriteLine($"Dataset has {rows.Count} rows — too small for train/test split. Training on all data.");
    Console.WriteLine("Add more rows for meaningful evaluation metrics.");
    model = pipeline.Fit(dataView);
}

// Save model for the prediction engine pool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

// Register pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };
    var result = pool.Predict(data);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability,
        Score = result.Score
    });
});

app.Run();

// --- Data models ---

public class CustomerData
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = string.Empty;
    public float PurchaseHistory { get; set; }
    public bool Label { get; set; }
}

public class ChurnPrediction
{
